event eProxyHeadRead: (key: int, requester: machine, podId: int);
event eProxyHeadReadResp: (key: int, value: int, has: bool);

machine StorageProxy {
    var db: machine;

    var queue: seq[(isWrite: bool, key: int, value: int, respTo: machine, podId: int)];
    var pendingReads: seq[(key: int, podId: int, respTo: machine)];
    var pendingWrites: seq[(key: int, value: int, podId: int, respTo: machine)];

    var knownPods: set[machine];
    var lastVal: map[int, int];
    var lastVer: map[int, int];

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            queue = default(seq[(isWrite: bool, key: int, value: int, respTo: machine, podId: int)]);
            pendingReads = default(seq[(key: int, podId: int, respTo: machine)]);
            pendingWrites = default(seq[(key: int, value: int, podId: int, respTo: machine)]);
            knownPods = default(set[machine]);
            lastVal = default(map[int, int]);
            lastVer = default(map[int, int]);
            goto Ready;
        }
    }

    state Ready {
        on eStorageRead do (req: (caller: machine, key: int, podId: int)) {
            var item: (isWrite: bool, key: int, value: int, respTo: machine, podId: int);
            announce eMonitorProxyRequestIssued, (key = req.key, podId = req.podId, isWrite = false);
            knownPods += (req.caller);
            item = (isWrite = false, key = req.key, value = 0, respTo = req.caller, podId = req.podId);
            queue += (sizeof(queue), item);
            announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = false, pending = sizeof(queue));
            MaybePump();
        }

        on eStorageWrite do (req: (caller: machine, key: int, value: int, podId: int)) {
            var item: (isWrite: bool, key: int, value: int, respTo: machine, podId: int);
            announce eMonitorProxyRequestIssued, (key = req.key, podId = req.podId, isWrite = true);
            knownPods += (req.caller);
            item = (isWrite = true, key = req.key, value = req.value, respTo = req.caller, podId = req.podId);
            queue += (sizeof(queue), item);
            announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true, pending = sizeof(queue));
            MaybePump();
        }

        on eProxyHeadRead do (req: (key: int, requester: machine, podId: int)) {
            var hasVal: bool;
            var val: int;
            announce eMonitorProxyRequestIssued, (key = req.key, podId = req.podId, isWrite = false);
            knownPods += (req.requester);
            hasVal = req.key in lastVal;
            if (hasVal) {
                val = lastVal[req.key];
                send req.requester, eProxyHeadReadResp, (key = req.key, value = val, has = true);
                announce eMonitorProxyResponseDelivered, (key = req.key, podId = req.podId, isWrite = false);
            } else {
                send req.requester, eProxyHeadReadResp, (key = req.key, value = 0, has = false);
                announce eMonitorProxyResponseDelivered, (key = req.key, podId = req.podId, isWrite = false);
            }
            MaybePump();
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var i: int;
            var found: bool;
            var entry: (key: int, podId: int, respTo: machine);
            i = 0;
            found = false;
            while (i < sizeof(pendingReads)) {
                if (pendingReads[i].key == resp.key) {
                    found = true;
                    break;
                }
                i = i + 1;
            }
            if (found) {
                entry = pendingReads[i];
                pendingReads -= (i);
                send entry.respTo, eStorageReadResp, (key = resp.key, value = resp.value);
                announce eMonitorProxyResponseDelivered, (key = resp.key, podId = entry.podId, isWrite = false);
            }
            MaybePump();
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var i: int;
            var found: bool;
            var entry: (key: int, value: int, podId: int, respTo: machine);
            var ver: int;
            i = 0;
            found = false;
            while (i < sizeof(pendingWrites)) {
                if (pendingWrites[i].key == resp.key) {
                    found = true;
                    break;
                }
                i = i + 1;
            }
            if (found) {
                entry = pendingWrites[i];
                pendingWrites -= (i);

                if (resp.success) {
                    lastVal[resp.key] = resp.value;
                    if (resp.key in lastVer) {
                        ver = lastVer[resp.key] + 1;
                    } else {
                        ver = 1;
                    }
                    lastVer[resp.key] = ver;
                }

                send entry.respTo, eStorageWriteResp, (key = resp.key, success = resp.success, value = resp.value);
                announce eMonitorProxyResponseDelivered, (key = resp.key, podId = entry.podId, isWrite = true);
            }
            MaybePump();
        }
    }

    fun MaybePump() {
        if (sizeof(queue) > 0) {
            if ($) {
                ForwardOne();
            } else {
                announce eMonitorProxyHold, (pending = sizeof(queue));
            }
        }
    }

    fun ForwardOne() {
        var idx: int;
        var item: (isWrite: bool, key: int, value: int, respTo: machine, podId: int);
        var outR: (key: int, podId: int, respTo: machine);
        var outW: (key: int, value: int, podId: int, respTo: machine);

        idx = choose(sizeof(queue));
        item = queue[idx];
        queue -= (idx);

        announce eMonitorProxyForward, (key = item.key, podId = item.podId, isWrite = item.isWrite, pending = sizeof(queue));

        if (item.isWrite) {
            outW = (key = item.key, value = item.value, podId = item.podId, respTo = item.respTo);
            pendingWrites += (sizeof(pendingWrites), outW);
            send db, eStorageWrite, (caller = this, key = item.key, value = item.value, podId = item.podId);
        } else {
            outR = (key = item.key, podId = item.podId, respTo = item.respTo);
            pendingReads += (sizeof(pendingReads), outR);
            send db, eStorageRead, (caller = this, key = item.key, podId = item.podId);
        }
    }
}

machine CacheNode {
    var proxy: machine;
    var podId: int;

    var readWaiters: map[int, seq[machine]];
    var readInFlight: set[int];

    var writeWaiters: map[int, seq[(client: machine, value: int)]];
    var writeInFlight: set[int];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;
            readWaiters = default(map[int, seq[machine]]);
            readInFlight = default(set[int]);
            writeWaiters = default(map[int, seq[(client: machine, value: int)]]);
            writeInFlight = default(set[int]);
            goto Ready;
        }
    }

    state Ready {
        on eClientRead do (req: (client: machine, key: int)) {
            var lst: seq[machine];
            if (req.key in readWaiters) {
                lst = readWaiters[req.key];
            } else {
                lst = default(seq[machine]);
            }
            lst += (sizeof(lst), req.client);
            readWaiters[req.key] = lst;

            if (!(req.key in readInFlight)) {
                readInFlight += (req.key);
                announce eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = false);
                send proxy, eProxyHeadRead, (key = req.key, requester = this, podId = podId);
            }
        }

        on eProxyHeadReadResp do (resp: (key: int, value: int, has: bool)) {
            var lst: seq[machine];
            var i: int;
            announce eMonitorProxyResponseDelivered, (key = resp.key, podId = podId, isWrite = false);

            if (!(resp.key in readWaiters)) {
                return;
            }

            if (resp.has) {
                lst = readWaiters[resp.key];
                i = 0;
                while (i < sizeof(lst)) {
                    send lst[i], eReadResp, (key = resp.key, value = resp.value, fromCache = true);
                    i = i + 1;
                }
                readWaiters -= (resp.key);
                readInFlight -= (resp.key);
            } else {
                announce eMonitorProxyRequestIssued, (key = resp.key, podId = podId, isWrite = false);
                send proxy, eStorageRead, (caller = this, key = resp.key, podId = podId);
            }
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var lst: seq[machine];
            var i: int;
            announce eMonitorProxyResponseDelivered, (key = resp.key, podId = podId, isWrite = false);

            if (resp.key in readWaiters) {
                lst = readWaiters[resp.key];
                i = 0;
                while (i < sizeof(lst)) {
                    send lst[i], eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                    i = i + 1;
                }
                readWaiters -= (resp.key);
            }
            if (resp.key in readInFlight) {
                readInFlight -= (resp.key);
            }
        }

        on eClientWrite do (req: (client: machine, key: int, value: int)) {
            var lst: seq[(client: machine, value: int)];
            var pair: (client: machine, value: int);
            if (req.key in writeWaiters) {
                lst = writeWaiters[req.key];
            } else {
                lst = default(seq[(client: machine, value: int)]);
            }
            pair = (client = req.client, value = req.value);
            lst += (sizeof(lst), pair);
            writeWaiters[req.key] = lst;

            if (!(req.key in writeInFlight)) {
                writeInFlight += (req.key);
                announce eMonitorProxyRequestIssued, (key = req.key, podId = podId, isWrite = true);
                send proxy, eStorageWrite, (caller = this, key = req.key, value = lst[0].value, podId = podId);
            }
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var lst: seq[(client: machine, value: int)];
            var head: (client: machine, value: int);
            announce eMonitorProxyResponseDelivered, (key = resp.key, podId = podId, isWrite = true);

            assert resp.key in writeWaiters, "Write response for unknown key";
            lst = writeWaiters[resp.key];
            head = lst[0];
            send head.client, eWriteResp, (key = resp.key, success = resp.success);
            lst -= (0);

            if (sizeof(lst) > 0) {
                writeWaiters[resp.key] = lst;
                announce eMonitorProxyRequestIssued, (key = resp.key, podId = podId, isWrite = true);
                send proxy, eStorageWrite, (caller = this, key = resp.key, value = lst[0].value, podId = podId);
            } else {
                writeWaiters -= (resp.key);
                if (resp.key in writeInFlight) {
                    writeInFlight -= (resp.key);
                }
            }
        }
    }
}
